19	ALFPWorldMapPlayerController::ALFPWorldMapPlayerController()
20	{
21		CameraOffset = FVector::ZeroVector;
22	
23		// 创建世界地图编辑器组件
24		WorldMapEditorComponent = CreateDefaultSubobject<ULFPWorldMapEditorComponent>(TEXT("WorldMapEditorComponent"));
25	}
