127	// ============== 输入处理 ==============
128	
129	void ALFPWorldMapPlayerController::OnConfirmAction(const FInputActionValue& Value)
130	{
131		bIsDragging = false;
132		if (DragTime > DragThresholdTime)
133		{
134			DragTime = 0.f;
135			return;
136		}
137		DragTime = 0.f;
138	
139		// 编辑器模式优先处理
140		if (WorldMapEditorComponent && WorldMapEditorComponent->IsEditorActive())
141		{
142			// 射线检测点击的节点
143			FHitResult HitResult;
144			GetHitResultUnderCursor(ECC_Visibility, false, HitResult);
145			ALFPWorldMapNode* ClickedNode = Cast<ALFPWorldMapNode>(HitResult.GetActor());
146	
147			ELFPWorldMapEditorTool CurrentTool = WorldMapEditorComponent->GetCurrentTool();
148	
149			switch (CurrentTool)
150			{
151			case ELFPWorldMapEditorTool::WMET_PlaceNode:
152				{
153					// 射线投射到 Z=0 平面获取世界坐标
154					FVector WorldOrigin, WorldDirection;
155					DeprojectMousePositionToWorld(WorldOrigin, WorldDirection);
156					if (FMath::Abs(WorldDirection.Z) > KINDA_SMALL_NUMBER)
157					{
158						float T = -WorldOrigin.Z / WorldDirection.Z;
159						FVector HitPoint = WorldOrigin + WorldDirection * T;
160						WorldMapEditorComponent->PlaceNodeAt(FVector2D(HitPoint.X, HitPoint.Y));
161					}
162				}
163				break;
164	
165			case ELFPWorldMapEditorTool::WMET_RemoveNode:
166				if (ClickedNode)
167				{
168					WorldMapEditorComponent->SelectNode(ClickedNode);
169					WorldMapEditorComponent->RemoveSelectedNode();
170				}
171				break;
172	
173			case ELFPWorldMapEditorTool::WMET_MoveNode:
174				if (ClickedNode)
175				{
176					WorldMapEditorComponent->SelectNode(ClickedNode);
177				}
178				else if (WorldMapEditorComponent->GetSelectedNode())
179				{
180					// 移动到点击位置
181					FVector WorldOrigin, WorldDirection;
182					DeprojectMousePositionToWorld(WorldOrigin, WorldDirection);
183					if (FMath::Abs(WorldDirection.Z) > KINDA_SMALL_NUMBER)
184					{
185						float T = -WorldOrigin.Z / WorldDirection.Z;
186						FVector HitPoint = WorldOrigin + WorldDirection * T;
187						WorldMapEditorComponent->MoveSelectedNodeTo(FVector2D(HitPoint.X, HitPoint.Y));
188					}
189				}
190				break;
191	
192			case ELFPWorldMapEditorTool::WMET_ConnectEdge:
193				if (ClickedNode)
194				{
195					WorldMapEditorComponent->HandleEdgeConnection(ClickedNode);
196				}
197				break;
198	
199			case ELFPWorldMapEditorTool::WMET_RemoveEdge:
200				if (ClickedNode)
201				{
202					WorldMapEditorComponent->HandleEdgeRemoval(ClickedNode);
203				}
204				break;
205	
206			case ELFPWorldMapEditorTool::WMET_SetNodeParams:
207				if (ClickedNode)
208				{
209					WorldMapEditorComponent->SelectNode(ClickedNode);
210					WorldMapEditorComponent->ApplyParamsToSelectedNode();
211				}
212				break;
213	
214			default:
215				break;
216			}
217			return;
218		}
219	
220		// 游戏模式：棋子移动中屏蔽点击
221		ALFPWorldMapManager* Manager = GetWorldMapManager();
222		if (Manager && Manager->IsPawnMoving()) return;
223	
224		// 游戏模式：点击节点移动或进入
225		FHitResult HitResult;
226		GetHitResultUnderCursor(ECC_Visibility, false, HitResult);
227		ALFPWorldMapNode* ClickedNode = Cast<ALFPWorldMapNode>(HitResult.GetActor());
228	
229		if (ClickedNode)
230		{
231			if (!Manager || !Manager->GetPlayerState()) return;
232	
233			int32 CurrentNodeID = Manager->GetPlayerState()->CurrentNodeID;
234	
235			// 点击当前节点 → 进入节点
236			if (ClickedNode->NodeID == CurrentNodeID)
237			{
238				EnterNode(ClickedNode);
239				return;
240			}
241	
242			// 点击相邻可达节点 → 移动
243			TArray<int32> ReachableIDs = Manager->GetPlayerState()->GetReachableNodeIDs(Manager);
244			if (ReachableIDs.Contains(ClickedNode->NodeID))
245			{
246				MoveToNode(ClickedNode);
247			}
248			else
249			{
250				// 不可达，只选中
251				SelectNode(ClickedNode);
252			}
253		}
254	}
