256	void ALFPWorldMapPlayerController::OnCancelAction(const FInputActionValue& Value)
257	{
258		// 取消选中和可达高亮
259		ClearReachableHighlight();
260		if (SelectedNode)
261		{
262			SelectedNode->SetHighlighted(false);
263			SelectedNode = nullptr;
264		}
265	}
266	
267	void ALFPWorldMapPlayerController::OnToggleEditorAction(const FInputActionValue& Value)
268	{
269		if (!WorldMapEditorComponent) return;
270	
271		WorldMapEditorComponent->ToggleEditorMode();
272	
273		if (WorldMapEditorComponent->IsEditorActive())
274		{
275			// 创建或显示编辑器 Widget
276			if (!WorldMapEditorWidget && WorldMapEditorWidgetClass)
277			{
278				WorldMapEditorWidget = CreateWidget<ULFPWorldMapEditorWidget>(this, WorldMapEditorWidgetClass);
279				if (WorldMapEditorWidget)
280				{
281					WorldMapEditorWidget->AddToViewport();
282					WorldMapEditorWidget->InitializeEditor(WorldMapEditorComponent);
283				}
284			}
285			else if (WorldMapEditorWidget)
286			{
287				WorldMapEditorWidget->SetVisibility(ESlateVisibility::Visible);
288			}
289	
290			bShowMouseCursor = true;
291		}
292		else
293		{
294			// 隐藏编辑器 Widget
295			if (WorldMapEditorWidget)
296			{
297				WorldMapEditorWidget->SetVisibility(ESlateVisibility::Collapsed);
298			}
299		}
300	}
