302	// ============== 相机操作 ==============
303	
304	void ALFPWorldMapPlayerController::OnCameraPan(const FInputActionValue& Value)
305	{
306		FVector2D PanInput = Value.Get<FVector2D>();
307		CameraOffset += FVector(PanInput.X, PanInput.Y, 0) * CameraPanSpeed * GetWorld()->GetDeltaSeconds();
308	}
309	
310	void ALFPWorldMapPlayerController::OnCameraDragStarted(const FInputActionValue& Value)
311	{
312		bIsDragging = true;
313		DragTime = 0.f;
314		GetMousePosition(DragStartPosition.X, DragStartPosition.Y);
315	}
316	
317	void ALFPWorldMapPlayerController::OnCameraDragTriggered(const FInputActionValue& Value)
318	{
319		if (!bIsDragging) return;
320	
321		FVector2D CurrentMousePos;
322		GetMousePosition(CurrentMousePos.X, CurrentMousePos.Y);
323		FVector2D Delta = CurrentMousePos - DragStartPosition;
324	
325		CameraOffset -= FVector(-Delta.Y, Delta.X, 0) * CameraDragSpeed;
326		DragStartPosition = CurrentMousePos;
327	}
328	
329	void ALFPWorldMapPlayerController::OnCameraDragCompleted(const FInputActionValue& Value)
330	{
331		bIsDragging = false;
332	}
333	
334	void ALFPWorldMapPlayerController::OnCameraZoom(const FInputActionValue& Value)
335	{
336		float ZoomDelta = Value.Get<float>();
337		CurrentZoom = FMath::Clamp(CurrentZoom - ZoomDelta * CameraZoomSpeed, MinZoomDistance, MaxZoomDistance);
338	
339		// 应用缩放到相机
340		if (APlayerCameraManager* CameraManager = PlayerCameraManager)
341		{
342			FVector CameraLocation = CameraManager->GetCameraLocation();
343			CameraLocation.Z = CurrentZoom;
344			CameraManager->SetManualCameraFade(0.f, FLinearColor::Black, false);
345		}
346	}
