348	// ============== 节点交互 ==============
349	
350	void ALFPWorldMapPlayerController::SelectNode(ALFPWorldMapNode* Node)
351	{
352		// 取消之前的选中
353		if (SelectedNode)
354		{
355			SelectedNode->SetHighlighted(false);
356		}
357	
358		SelectedNode = Node;
359	
360		if (SelectedNode)
361		{
362			SelectedNode->SetHighlighted(true);
363		}
364	}
