366	void ALFPWorldMapPlayerController::MoveToNode(ALFPWorldMapNode* Node)
367	{
368		if (!Node) return;
369	
370		ALFPWorldMapManager* Manager = GetWorldMapManager();
371		if (!Manager) return;
372	
373		// 棋子移动中不允许操作
374		if (Manager->IsPawnMoving()) return;
375	
376		ClearReachableHighlight();
377	
378		// 记录目标节点，移动完成后自动进入
379		PendingEnterNode = Node;
380	
381		// 绑定棋子移动完成回调
