473	void ALFPWorldMapPlayerController::EnterBattle(ALFPWorldMapNode* BattleNode)
474	{
475		if (!BattleNode) return;
476	
477		ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance());
478		if (!GI) return;
479	
480		ALFPWorldMapManager* Manager = GetWorldMapManager();
481		if (!Manager) return;
482	
483		// 保存世界地图快照
484		FLFPWorldMapSnapshot Snapshot;
485		Snapshot.WorldMapName = Manager->GetCurrentWorldMapName();
486		if (ULFPWorldMapPlayerState* PS = Manager->GetPlayerState())
487		{
488			Snapshot.CurrentNodeID = PS->CurrentNodeID;
489			Snapshot.CurrentTurn = PS->CurrentTurn;
490			Snapshot.VisitedNodeIDs = PS->VisitedNodeIDs;
491			Snapshot.RevealedNodeIDs = PS->RevealedNodeIDs;
492		}
493	
494		// 收集已触发节点
495		for (const auto& Pair : Manager->GetNodeMap())
496		{
497			if (Pair.Value && Pair.Value->bHasBeenTriggered)
498			{
499				Snapshot.TriggeredNodeIDs.Add(Pair.Key);
500			}
501		}
502	
503		GI->SaveWorldMapSnapshot(Snapshot);
504	
505		// 设置战斗请求
506		FLFPBattleRequest Request;
507		Request.SourceNodeID = BattleNode->NodeID;
508		Request.BattleMapName = BattleNode->BattleMapName;
509		Request.StarRating = BattleNode->StarRating;
510		Request.bCanEscape = BattleNode->bCanEscape;
511		Request.BaseGoldReward = BattleNode->BaseGoldReward;
512		Request.BaseFoodReward = BattleNode->BaseFoodReward;
513		GI->SetBattleRequest(Request);
514	
515		// 切换到战斗关卡
516		GI->TransitionToBattle(TEXT(""));
517	}
