70	TArray<int32> ULFPWorldMapPlayerState::GetReachableNodeIDs(ALFPWorldMapManager* Manager) const
71	{
72		TArray<int32> Result;
73		if (!Manager) return Result;
74	
75		TArray<ALFPWorldMapNode*> Neighbors = Manager->GetNeighbors(CurrentNodeID);
76		for (ALFPWorldMapNode* Neighbor : Neighbors)
77		{
78			if (!Neighbor) continue;
79	
80			// 检查解锁条件（前置节点必须已访问）
81			bool bUnlocked = true;
82			if (!Neighbor->PrerequisiteNodeIDs.IsEmpty())
83			{
84				TArray<FString> PrereqIDs;
85				Neighbor->PrerequisiteNodeIDs.ParseIntoArray(PrereqIDs, TEXT(";"), true);
86				for (const FString& IDStr : PrereqIDs)
87				{
88					int32 PrereqID = FCString::Atoi(*IDStr);
89					if (!VisitedNodeIDs.Contains(PrereqID))
90					{
91						bUnlocked = false;
92						break;
93					}
94				}
95			}
96	
97			if (bUnlocked)
98			{
99				Result.Add(Neighbor->NodeID);
100			}
101		}
102	
103		return Result;
104	}
